sp_widget.client_script:
api.controller = function($scope, spUtil, $location, $window, mandatoryValidator) {
    var c = this;

  	c.save = function() {

			console.log("BUTTON CLICKED");

			var result = mandatoryValidator.validate(c.data.f);

			if (!result.valid) {
					spUtil.addErrorMessage(result.message);
					return;
			}

			// 🔥 CHANGE ACTION NAME
			c.data.action = "generate";

			c.data.form = { _fields: c.data.f._fields };

			console.log("Sending request to server...");

			c.server.get({
					action: "generate",
					form: { _fields: c.data.f._fields }
			}).then(function(response) {

				console.log("Response received:", response);

					var res = response.data;

					// ❌ ERROR
					if (res.valid === false) {
							spUtil.addErrorMessage(res.message);
							return;
					}

					// ✅ EXISTING
					if (res.exists) {
							spUtil.addInfoMessage("Statement already exists. Redirecting...");
					} 
					// ✅ NEW
					else {
							spUtil.addInfoMessage("Statement generated successfully");
					}

					var url = "?id=incentive_statement_view&statement_id=" + res.sys_id;

					setTimeout(function() {

							$location.url(url);
					}, 100);

			});
	};

    c.goBack = function () {
        const prev = sessionStorage.getItem('prevPage');
        if (prev) {

            $location.url(prev);
        } else {
            window.history.back();
        }
    };
};

