sp_widget.script:
(function() {

    // ✅ HARDCODE TABLE
    data.table = "x_ctans_incentnow_incentive_statement";

    data.sys_id = (input && input.sys_id) || $sp.getParameter('sys_id') || "-1";
    data.view   = "portal_view";

    data.f = $sp.getForm(data.table, data.sys_id, '', data.view);
		if (data.f._fields.fiscal_period) {
    data.f._fields.fiscal_period.attributes =
        (data.f._fields.fiscal_period.attributes || '') +
        ',ref_ac_order_by=period_number';
}
    data.f = new x_ctans_incentnow.IncentNowPortalUtils().applyPlaceholders(data.f);

    data.table_label = "Incentive Statement";
    data.fetchButtonName = "Generate Statement";

    // ================= SAVE =================
		 if (input && input.action == "generate") {

				if (!input.form || !input.form._fields) {
						data.valid = false;
						data.message = "Form data missing";
						return;
				}

				var fields = input.form._fields;

				// ✅ SAFE EXTRACTION (IMPORTANT)
				var user   = fields.user && fields.user.value;
				var plan   = fields.plan && fields.plan.value;
				var period = fields.fiscal_period && fields.fiscal_period.value;
			 	var year = fields.fiscal_year && fields.fiscal_year.value;

				if (!user || !plan || !period || !year) {
						data.valid = false;
						data.message = "Missing required fields";
						return;
				}

				// ===============================
				// 🔍 STEP 1: CHECK IF EXISTS
				// ===============================
				var dupGR = new GlideRecordSecure('x_ctans_incentnow_incentive_statement');
				dupGR.addQuery('user', user);
				dupGR.addQuery('fiscal_period', period);
			 	dupGR.addQuery('fiscal_year', year);
				dupGR.setLimit(1);
				dupGR.query();

				if (dupGR.next()) {
						data.exists = true;
						data.sys_id = dupGR.getUniqueValue();
						return;
				}

				// ===============================
				// ⚙️ STEP 2: CREATE + PROCESS
				// ===============================
				var statementGR = new GlideRecordSecure('x_ctans_incentnow_incentive_statement');
				statementGR.initialize();

				statementGR.setValue('user', user);
				statementGR.setValue('plan', plan);
				statementGR.setValue('fiscal_period', period);
			  statementGR.setValue('fiscal_year', year);

			 	statementGR.user.getRefRecord();
				statementGR.plan.getRefRecord();
				statementGR.fiscal_period.getRefRecord();

				try {
						var processor = new IncentNowStatementProcessor();
						var result = processor.process(statementGR);

						if (!result || !result.valid) {
								data.valid = false;
								data.message = result.message || "Processing failed";
								return;
						}

						data.valid = true;
						data.exists = false;
						data.sys_id = result.record.getUniqueValue();
						data.total = result.total;

				} catch (e) {
						data.valid = false;
						data.message = "Error: " + e.message;
				}
		}
})();
